css:
body {
  font-family: -apple-system, 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
  background: linear-gradient(180deg, #C6E8F5 0%, #7EC8E3 25%, #4AACDA 60%, #2E8EC4 100%) !important;
  background-attachment: fixed !important;
}
input, select, textarea, button {
  font-family: -apple-system, 'Segoe UI', 'Helvetica Neue', Arial, sans-serif;
}
.header {
  background: linear-gradient(
    180deg,
    color-mix(in srgb, #EDF6FC var(--ts-opacity-header), transparent) 0%,
    color-mix(in srgb, #D4E8F5 var(--ts-opacity-header), transparent) 100%
  ) !important;
  border-bottom: 2px solid color-mix(in srgb, #9CC8E0 var(--ts-opacity-header), transparent) !important;
  box-shadow: 0 2px 6px rgba(0, 60, 120, 0.08),
    inset 0 1px 1px rgba(255,255,255,0.9),
    inset 0 -1px 1px rgba(0,80,140,0.04);
}
.header::after {
  content: '';
  position: absolute;
  top: 1px; left: 12px; right: 12px;
  height: 50%;
  background: linear-gradient(180deg, rgba(255,255,255,0.7) 0%, rgba(255,255,255,0.08) 100%);
  border-radius: 0 0 50% 50% / 0 0 100% 100%;
  pointer-events: none;
  z-index: 0;
  opacity: var(--ts-opacity-header-alpha);
}
.header > * { position: relative; z-index: 1; }
.sidebar {
  background: linear-gradient(180deg, #D0E4F2 0%, #E0EEF7 40%, #F4FAFD 100%) !important;
  border-right: 2px solid #9CC8E0 !important;
  box-shadow: 2px 0 6px rgba(0, 60, 120, 0.05);
}
.album-row.album-row-header, .album-row.album-row-header:hover {
  background: linear-gradient(
    180deg,
    color-mix(in srgb, #EDF6FC var(--ts-row-surface-opacity, var(--ts-opacity-row-header-background)), transparent) 0%,
    color-mix(in srgb, #D4E8F5 var(--ts-row-surface-opacity, var(--ts-opacity-row-header-background)), transparent) 100%
  ) !important;
  border: 1.5px solid color-mix(in srgb, #A8D0E8 var(--ts-row-surface-opacity, var(--ts-opacity-row-header-background)), transparent) !important;
  box-shadow: 0 2px 4px rgba(0, 60, 120, 0.06),
    inset 0 1px 1px rgba(255,255,255,0.9),
    inset 0 -1px 1px rgba(0,80,140,0.04);
  overflow: hidden;
  color: #4A7A9A !important;
}
.album-row.album-row-header::after {
  display: block !important;
  opacity: var(--ts-opacity-row-header-background-alpha) !important;
}
button {
  position: relative;
  overflow: hidden;
  background: linear-gradient(180deg, #D8EDFB 0%, #B8D8F0 100%) !important;
  border: 2px solid #8CC0DD !important;
  border-radius: 20px !important;
  color: #1A4060 !important;
  box-shadow: 0 2px 4px rgba(0, 60, 120, 0.10),
    inset 0 1px 1px rgba(255,255,255,0.8),
    inset 0 -1px 1px rgba(0,80,140,0.06);
  transition: all 0.15s ease;
}
button::after {
  content: '';
  position: absolute;
  top: 2px; left: 12%; right: 12%;
  height: 45%;
  background: linear-gradient(180deg, rgba(255,255,255,0.7) 0%, rgba(255,255,255,0.1) 100%);
  border-radius: 0 0 50% 50% / 0 0 100% 100%;
  pointer-events: none;
}
button:hover {
  background: linear-gradient(180deg, #C4E4F8 0%, #90C4E8 100%) !important;
  border-color: #60A8D0 !important;
  box-shadow: 0 3px 8px rgba(0, 60, 120, 0.16),
    inset 0 1px 1px rgba(255,255,255,0.7),
    inset 0 -1px 1px rgba(0,80,140,0.08);
}
.album-card {
  background: linear-gradient(
    180deg,
    color-mix(in srgb, #FFFFFF var(--ts-opacity-card), transparent) 0%,
    color-mix(in srgb, #F6FBFE var(--ts-opacity-card), transparent) 100%
  ) !important;
  border: 1.5px solid color-mix(in srgb, #A8D0E8 var(--ts-opacity-card), transparent) !important;
  border-radius: 14px !important;
  box-shadow: 0 2px 8px rgba(0, 60, 120, 0.08);
  overflow: hidden;
  transition: border-color 0.15s, box-shadow 0.15s, background 0.15s;
}
.album-card:hover {
  background: linear-gradient(
    180deg,
    color-mix(in srgb, #C4E4F8 var(--ts-opacity-card), transparent) 0%,
    color-mix(in srgb, #90C4E8 var(--ts-opacity-card), transparent) 100%
  ) !important;
  border-color: color-mix(in srgb, #60A8D0 var(--ts-opacity-card), transparent) !important;
  box-shadow: 0 4px 16px rgba(0, 60, 120, 0.18);
}
.card-info {
  position: relative;
  overflow: hidden;
  background: linear-gradient(
    180deg,
    color-mix(in srgb, #EDF6FC var(--ts-opacity-card), transparent) 0%,
    color-mix(in srgb, #D4E8F5 var(--ts-opacity-card), transparent) 100%
  ) !important;
  border-radius: 0 !important;
  box-shadow: inset 0 1px 1px rgba(255,255,255,0.9),
    inset 0 -1px 1px rgba(0,80,140,0.04);
}
.card-info::after {
  content: '';
  position: absolute;
  top: 1px; left: 8px; right: 8px;
  height: 50%;
  background: linear-gradient(180deg, rgba(255,255,255,0.75) 0%, rgba(255,255,255,0.1) 100%);
  border-radius: 0 0 50% 50% / 0 0 100% 100%;
  pointer-events: none;
  opacity: var(--ts-opacity-card-alpha);
}
.card-info > * { position: relative; z-index: 1; }
.album-card:hover .card-info {
  background: linear-gradient(
    180deg,
    color-mix(in srgb, #C4E4F8 var(--ts-opacity-card), transparent) 0%,
    color-mix(in srgb, #90C4E8 var(--ts-opacity-card), transparent) 100%
  ) !important;
}
.card-art {
  border-radius: 0 !important;
}
.album-row {
  position: relative;
  border-radius: 10px !important;
  background: linear-gradient(
    180deg,
    color-mix(in srgb, #EDF6FC var(--ts-row-surface-opacity, var(--ts-opacity-row)), transparent) 0%,
    color-mix(in srgb, #D4E8F5 var(--ts-row-surface-opacity, var(--ts-opacity-row)), transparent) 100%
  ) !important;
  border: 1.5px solid color-mix(in srgb, #A8D0E8 var(--ts-row-surface-opacity, var(--ts-opacity-row)), transparent) !important;
  box-shadow: 0 2px 4px rgba(0, 60, 120, 0.06),
    inset 0 1px 1px rgba(255,255,255,0.9),
    inset 0 -1px 1px rgba(0,80,140,0.04);
  overflow: hidden;
}
.album-row::after {
  content: '';
  position: absolute;
  top: 1px; left: 8px; right: 8px;
  height: 45%;
  background: linear-gradient(180deg, rgba(255,255,255,0.75) 0%, rgba(255,255,255,0.1) 100%);
  border-radius: 0 0 50% 50% / 0 0 100% 100%;
  pointer-events: none;
  z-index: 0;
  opacity: var(--ts-row-surface-alpha, var(--ts-opacity-row-alpha));
}
.album-row:hover {
  background: linear-gradient(
    180deg,
    color-mix(in srgb, #C4E4F8 var(--ts-opacity-row), transparent) 0%,
    color-mix(in srgb, #90C4E8 var(--ts-opacity-row), transparent) 100%
  ) !important;
  border-color: color-mix(in srgb, #60A8D0 var(--ts-opacity-row), transparent) !important;
}
.album-row > * { position: relative; z-index: 1; }
.modal {
  background: linear-gradient(180deg, #FFFFFF 0%, #F0F8FE 100%) !important;
  border: 2px solid #9CC8E0 !important;
  border-radius: 18px !important;
  box-shadow: 0 8px 32px rgba(0, 60, 120, 0.18);
}
input, select, textarea {
  border: 2px solid #A0C4DC !important;
  border-radius: 10px !important;
  background:
    linear-gradient(180deg,
      rgba(255,255,255,0.9) 0%,
      rgba(255,255,255,0.4) 40%,
      rgba(220,238,250,0.3) 50%,
      rgba(200,228,245,0.5) 100%),
    linear-gradient(180deg, #E8F2FA 0%, #D0E2F0 100%) !important;
  color: #1A3550 !important;
  box-shadow: 0 1px 3px rgba(0, 60, 120, 0.08),
    inset 0 1px 0 rgba(255,255,255,0.8),
    inset 0 -1px 0 rgba(0,80,140,0.05);
}
input:focus, select:focus, textarea:focus {
  border-color: #0088CC !important;
  box-shadow: 0 1px 3px rgba(0, 60, 120, 0.08),
    inset 0 1px 0 rgba(255,255,255,0.8),
    inset 0 -1px 0 rgba(0,80,140,0.05),
    0 0 0 3px rgba(0, 136, 204, 0.15);
}
a, .artist-link { color: #0078B0 !important; }
a:hover, .artist-link:hover { color: #00AAEE !important; }
::selection { background: #0088CC; color: #FFFFFF; }
